      "size": 566,
      "annotations": {
        "vnd.docker.reference.digest": "sha256:b4185bd52d9cc53deecc9ee24c44a036b3613cf94edc592bfb2b84be87fd156f",
        "vnd.docker.reference.type": "attestation-manifest"
